import { useEffect, useState } from "react";
import { useNavigate } from "react-router-dom";
import axios from "axios";

import {
  LineChart,
  Line,
  XAxis,
  YAxis,
  Tooltip,
  CartesianGrid,
  PieChart,
  Pie,
  Cell,
  BarChart,
  Bar,
  Legend
} from "recharts";

import "./Dashboard.css";

/* API */
const API = "http://127.0.0.1:8000";

function Dashboard() {

  const navigate = useNavigate();

  const [kpis, setKpis] = useState(null);
  const [forecast, setForecast] = useState([]);
  const [prediction, setPrediction] = useState(null);
  const [risk, setRisk] = useState("");
  const [blockchain, setBlockchain] = useState("");
  const [riskData, setRiskData] = useState([]);
  const [comparisonData, setComparisonData] = useState([]);
  const [loading, setLoading] = useState(true);

  const COLORS = ["#22c55e", "#f59e0b", "#ef4444"];

  useEffect(() => {

    const token = localStorage.getItem("token");

    if (!token) {
      navigate("/");
      return;
    }

    loadDashboard(token);

  }, [navigate]);

  const loadDashboard = async (token) => {

    try {

      setLoading(true);

      const headers = {
        Authorization: `Bearer ${token}`
      };

      const [
        kpiRes,
        forecastRes,
        predictionRes,
        chartRes,
        anomalyRes,
        riskRes,
        blockchainRes
      ] = await Promise.all([
        axios.get(`${API}/kpis`, { headers }),
        axios.get(`${API}/revenue-forecast`, { headers }),
        axios.get(`${API}/forecast-revenue`, { headers }),
        axios.get(`${API}/chart-data`, { headers }),
        axios.get(`${API}/classify-risk-xgb`, { headers }),
        axios.get(`${API}/hash-ml-results`, { headers }),
        axios.get(`${API}/verify-integrity`, { headers })
      ]);

      setKpis(kpiRes.data);
      setForecast(forecastRes.data);
      setPrediction(predictionRes.data);
      setComparisonData(chartRes.data);

      const results = anomalyRes.data.results || [];

      let low = 0;
      let medium = 0;
      let high = 0;

      results.forEach(item => {

        if (item.classified_risk === "Low") low++;
        else if (item.classified_risk === "Medium") medium++;
        else if (item.classified_risk === "High") high++;

      });

      setRiskData([
        { name: "Low", value: low },
        { name: "Medium", value: medium },
        { name: "High", value: high }
      ]);

      setRisk(`Total Records Analysed: ${riskRes.data.total_records}`);
      setBlockchain(blockchainRes.data.status);

    }
    catch (error) {

      console.error("Dashboard Load Error:", error);
      alert("Error loading dashboard data");

    }
    finally {

      setLoading(false);

    }

  };

  const uploadCSV = async (e) => {

    const file = e.target.files[0];
    if (!file) return;

    const token = localStorage.getItem("token");

    const formData = new FormData();
    formData.append("file", file);

    try {

      await axios.post(`${API}/upload-csv`, formData, {
        headers: { Authorization: `Bearer ${token}` }
      });

      alert("CSV uploaded successfully");

      loadDashboard(token);

    }
    catch (error) {

      console.error(error);
      alert("CSV upload failed");

    }

  };

  const logout = () => {

    localStorage.removeItem("token");
    navigate("/");

  };

  if (loading) {

    return (
      <h2 style={{ textAlign: "center", marginTop: "120px" }}>
        Loading Financial Analytics Dashboard...
      </h2>
    );

  }

  const forecastChart = [...forecast];

  if (prediction) {

    forecastChart.push({
      month: "Next",
      revenue: prediction.next_month_prediction
    });

  }

  return (

    <div className="dashboard">

      <div className="sidebar">

        <h2>FinPulse</h2>

        <button onClick={logout}>Logout</button>

        <div className="security-card">
          <h3>Records Analysed</h3>
          <p>{risk}</p>
        </div>

        <div className="security-card">
          <h3>Blockchain Integrity</h3>
          <p>{blockchain}</p>
        </div>

      </div>

      <div className="main">

        <h1>Financial Analytics Dashboard</h1>

        <div className="upload-box">

          <h3>Upload Financial CSV</h3>

          <input
            type="file"
            accept=".csv"
            onChange={uploadCSV}
          />

        </div>

        <div className="kpi-container">

          <div className="kpi-card">
            <h3>Total Revenue</h3>
            <p>₹ {Number(kpis?.total_revenue || 0).toLocaleString()}</p>
          </div>

          <div className="kpi-card">
            <h3>Total Expense</h3>
            <p>₹ {Number(kpis?.total_expense || 0).toLocaleString()}</p>
          </div>

          <div className="kpi-card">
            <h3>Net Profit</h3>
            <p>₹ {Number(kpis?.net_profit || 0).toLocaleString()}</p>
          </div>

        </div>

        <div className="chart-row">

          <div className="chart-card">

            <h3>Revenue Forecast</h3>

            <LineChart width={500} height={300} data={forecastChart}>

              <CartesianGrid strokeDasharray="3 3" />

              <XAxis dataKey="month" />

              <YAxis />

              <Tooltip />

              <Line type="monotone" dataKey="revenue" stroke="#38bdf8" />

            </LineChart>

          </div>

          <div className="chart-card">

            <h3>Risk Distribution</h3>

            <PieChart width={350} height={300}>

              <Pie
                data={riskData}
                dataKey="value"
                cx="50%"
                cy="50%"
                outerRadius={100}
                label
              >

                {riskData.map((entry, index) => (
                  <Cell key={index} fill={COLORS[index]} />
                ))}

              </Pie>

              <Tooltip />

            </PieChart>

          </div>

        </div>

        <div className="chart-card">

          <h3>Revenue vs Expense</h3>

          <BarChart width={700} height={300} data={comparisonData}>

            <CartesianGrid strokeDasharray="3 3" />

            <XAxis dataKey="month" />

            <YAxis />

            <Tooltip />

            <Legend />

            <Bar dataKey="revenue" fill="#6366f1" />

            <Bar dataKey="expense" fill="#22c55e" />

          </BarChart>

        </div>

      </div>

    </div>

  );

}

export default Dashboard;
